CREATE OR REPLACE FUNCTION public.add_manual_item_to_grocery_list(list_id uuid, ingredient_name text, quantity numeric, unit_name text, notes text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$DECLARE
  ingredient_id bigint;
  manual_name text;
  unit_id uuid;
  item_id uuid;
BEGIN
  -- Find or create ingredient
  SELECT id INTO ingredient_id FROM ingredients WHERE name ILIKE ingredient_name;
  IF NOT FOUND THEN
    manual_name = ingredient_name;
  END IF;
  
  -- Find unit
  SELECT id INTO unit_id FROM units WHERE name = unit_name;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Unit "%" not found', unit_name;
  END IF;
  
  -- Insert manual item
  INSERT INTO grocery_list_items (
    grocery_list_id,
    ingredient_id,
    quantity,
    unit_id,
    notes,
    is_manual,
    manual_name,
    source_recipes
  ) VALUES (
    list_id,
    ingredient_id,
    quantity,
    unit_id,
    notes,
    true,
    manual_name,
    '{}'
  ) RETURNING id INTO item_id;
  
  RETURN item_id;
END;$function$
;

CREATE OR REPLACE FUNCTION public.add_recipe_to_grocery_list(list_id uuid, p_recipe_id uuid, servings_multiplier numeric DEFAULT 1.0)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$ 
BEGIN 
    INSERT INTO public.grocery_list_recipes (grocery_list_id, recipe_id, servings_multiplier) 
    VALUES (list_id, p_recipe_id, servings_multiplier) 
    ON CONFLICT (grocery_list_id, recipe_id) 
    DO UPDATE SET servings_multiplier = EXCLUDED.servings_multiplier; 
    
    RETURN true; 
END; 
$function$
;

CREATE OR REPLACE FUNCTION public.delete_old_anonymous_users()
 RETURNS TABLE(deleted_count integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$DECLARE
    total_deleted INTEGER;
BEGIN
    -- Delete anonymous users older than 24 hours from auth.users
    WITH deleted_users AS (
        DELETE FROM auth.users
        WHERE 
            -- Check if the user is anonymous (no email)
            email IS NULL 
            -- Check if the user is older than 24 hours
            AND created_at < NOW() - INTERVAL '24 hours'
        RETURNING id
    )
    SELECT COUNT(*) INTO total_deleted FROM deleted_users;

    RETURN QUERY SELECT total_deleted;
END;$function$
;

CREATE OR REPLACE FUNCTION public.find_best_unit_for_quantity(p_base_quantity numeric, p_unit_type text, p_preferred_system text DEFAULT 'imperial'::text)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
  best_unit_id uuid;
BEGIN
  -- Select unit that results in the most readable quantity (between 0.25 and 999)
  SELECT id INTO best_unit_id
  FROM (
    SELECT 
      u.id,
      ABS(LOG(p_base_quantity / NULLIF(u.base_conversion_factor, 0))) as log_distance,
      p_base_quantity / NULLIF(u.base_conversion_factor, 1) as converted_qty
    FROM units u
    WHERE u.type = p_unit_type
      AND u.base_conversion_factor IS NOT NULL
      AND u.system = p_preferred_system
      AND p_base_quantity / NULLIF(u.base_conversion_factor, 1) BETWEEN 0.25 AND 999
    ORDER BY log_distance ASC
    LIMIT 1
  ) suitable_units;
  
  -- Fallback to any unit of the correct type if no suitable unit found
  IF best_unit_id IS NULL THEN
    SELECT id INTO best_unit_id
    FROM units
    WHERE type = p_unit_type
      AND system = p_preferred_system
    ORDER BY display_order ASC
    LIMIT 1;
  END IF;
  
  RETURN best_unit_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.generate_simple_anonymous_username()
 RETURNS text
 LANGUAGE plpgsql
AS $function$DECLARE
    username text;
BEGIN
    username := 'anon_' || lower(replace(gen_random_uuid()::text, '-', ''));
    RETURN username;
END;$function$
;

CREATE OR REPLACE FUNCTION public.get_public_and_user_recipes()
 RETURNS TABLE(id uuid, name text, image_url text, created_by uuid, steps text[], servings bigint, created_at timestamp with time zone)
 LANGUAGE sql
 SECURITY DEFINER
AS $function$ 
SELECT id, name, image_url, created_by, steps, servings, created_at
FROM recipes
WHERE created_by = '6e0258f5-c980-47d2-a7ee-981e76e56333'
OR created_by = auth.uid();
$function$
;

CREATE OR REPLACE FUNCTION public.get_public_recipes()
 RETURNS TABLE(id uuid, name text, image_url text, created_by uuid, steps text[], servings bigint, created_at timestamp with time zone)
 LANGUAGE sql
 SECURITY DEFINER
AS $function$
    SELECT id, name, image_url, created_by, steps, servings, created_at 
    FROM recipes
    WHERE created_by = '6e0258f5-c980-47d2-a7ee-981e76e56333';
$function$
;

CREATE OR REPLACE FUNCTION public.handle_new_anonymous_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''
AS $function$DECLARE
    generated_display_name text;
BEGIN
    -- Only proceed if the provider type is 'Anonymous'
    IF NEW.raw_app_meta_data->>'Provider type' = 'Anonymous' THEN
        -- Generate a unique display name
        generated_display_name := 'anon_' || lower(replace(gen_random_uuid()::text, '-', ''));
        
        -- Ensure user_metadata exists and is a valid JSONB
        IF NEW.user_metadata IS NULL THEN
            NEW.user_metadata := '{}'::jsonb;
        END IF;
        
        -- Set the display name in user_metadata
        NEW.user_metadata := NEW.user_metadata || 
            jsonb_build_object('displayName', generated_display_name);
    END IF;
    
    RETURN NEW;
END;$function$
;

CREATE OR REPLACE FUNCTION public.regenerate_grocery_list_items(list_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$DECLARE
  recipe_record RECORD;
  ingredient_record RECORD;
  existing_item RECORD;
  total_base_quantity decimal;
  preferred_unit_id uuid;
  converted_quantity decimal;
BEGIN
  -- Delete all non-manual items first
  DELETE FROM grocery_list_items 
  WHERE grocery_list_id = list_id AND is_manual = false;
  
  -- Create temp table to collect ingredients without base conversion
  -- This will allow us to handle units without conversion separately
  CREATE TEMP TABLE temp_ingredient_no_conversion (
    ingredient_id bigint,
    unit_id uuid,
    total_quantity decimal,
    unit_type text,
    source_recipes uuid[],
    notes text,
    has_null_quantity boolean DEFAULT false,
    PRIMARY KEY (ingredient_id, unit_id)
  ) ON COMMIT DROP;
  
  -- Create temp table to collect all ingredient quantities in base units
  CREATE TEMP TABLE temp_ingredient_aggregation (
    ingredient_id bigint,
    total_base_quantity decimal,
    unit_type text,
    source_recipes uuid[],
    notes text,
    has_null_quantity boolean DEFAULT false,
    PRIMARY KEY (ingredient_id, unit_type)
  ) ON COMMIT DROP;
  
  -- Create temp table for ingredients with null quantities
  CREATE TEMP TABLE temp_null_quantity_ingredients (
    ingredient_id bigint,
    unit_id uuid,
    source_recipes uuid[],
    notes text,
    PRIMARY KEY (ingredient_id)
  ) ON COMMIT DROP;
  
  -- Loop through all recipes in the grocery list
  FOR recipe_record IN 
    SELECT glr.recipe_id, glr.servings_multiplier, r.servings as original_servings
    FROM grocery_list_recipes glr
    JOIN recipes r ON glr.recipe_id = r.id
    WHERE glr.grocery_list_id = list_id
  LOOP
    -- Calculate the scaling factor
    DECLARE
      scale_factor decimal := recipe_record.servings_multiplier / recipe_record.original_servings;
    BEGIN
      -- Loop through ingredients for this recipe (including null quantities)
      FOR ingredient_record IN
        SELECT 
          ri.ingredient_id,
          CASE 
            WHEN ri.unit_amount IS NOT NULL THEN ri.unit_amount * scale_factor 
            ELSE NULL 
          END as scaled_quantity,
          ri.unit_id,
          ri.note as notes,
          u.base_conversion_factor,
          u.type as unit_type,
          ri.unit_amount IS NULL as is_null_quantity
        FROM recipe_ingredients ri
        LEFT JOIN units u ON ri.unit_id = u.id
        WHERE ri.recipe_id = recipe_record.recipe_id
      LOOP
        -- Handle ingredients with null quantities
        IF ingredient_record.is_null_quantity THEN
          INSERT INTO temp_null_quantity_ingredients (
            ingredient_id,
            unit_id,
            source_recipes,
            notes
          )
          VALUES (
            ingredient_record.ingredient_id,
            ingredient_record.unit_id,
            ARRAY[recipe_record.recipe_id],
            ingredient_record.notes
          )
          ON CONFLICT (ingredient_id) DO UPDATE
          SET 
            -- Prefer non-blank unit over blank unit
            unit_id = CASE 
              WHEN temp_null_quantity_ingredients.unit_id = 'f97badf3-daeb-4f07-84df-9bd19e7726e8'::uuid 
                   AND EXCLUDED.unit_id != 'f97badf3-daeb-4f07-84df-9bd19e7726e8'::uuid 
              THEN EXCLUDED.unit_id
              ELSE temp_null_quantity_ingredients.unit_id
            END,
            source_recipes = array_cat(temp_null_quantity_ingredients.source_recipes, EXCLUDED.source_recipes),
            notes = CASE 
              WHEN temp_null_quantity_ingredients.notes IS NULL THEN EXCLUDED.notes
              WHEN EXCLUDED.notes IS NULL THEN temp_null_quantity_ingredients.notes
              WHEN temp_null_quantity_ingredients.notes = EXCLUDED.notes THEN temp_null_quantity_ingredients.notes
              ELSE temp_null_quantity_ingredients.notes || '; ' || EXCLUDED.notes
            END;
        -- Separate handling for units without base conversion
        ELSIF ingredient_record.base_conversion_factor IS NULL THEN
          -- Insert into temp table for no-conversion units
          INSERT INTO temp_ingredient_no_conversion (
            ingredient_id, 
            unit_id,
            total_quantity, 
            unit_type, 
            source_recipes, 
            notes
          )
          VALUES (
            ingredient_record.ingredient_id,
            ingredient_record.unit_id,
            ingredient_record.scaled_quantity,
            ingredient_record.unit_type,
            ARRAY[recipe_record.recipe_id],
            ingredient_record.notes
          )
          ON CONFLICT (ingredient_id, unit_id) DO UPDATE
          SET 
            total_quantity = temp_ingredient_no_conversion.total_quantity + EXCLUDED.total_quantity,
            source_recipes = array_cat(temp_ingredient_no_conversion.source_recipes, EXCLUDED.source_recipes),
            notes = CASE 
              WHEN temp_ingredient_no_conversion.notes IS NULL THEN EXCLUDED.notes
              WHEN EXCLUDED.notes IS NULL THEN temp_ingredient_no_conversion.notes
              WHEN temp_ingredient_no_conversion.notes = EXCLUDED.notes THEN temp_ingredient_no_conversion.notes
              ELSE temp_ingredient_no_conversion.notes || '; ' || EXCLUDED.notes
            END;
        ELSE
          -- Normal processing for units with base conversion
          DECLARE
            base_quantity decimal := ingredient_record.scaled_quantity * ingredient_record.base_conversion_factor;
          BEGIN
            -- Insert or update in temp table
            INSERT INTO temp_ingredient_aggregation (
              ingredient_id, 
              total_base_quantity, 
              unit_type, 
              source_recipes, 
              notes
            )
            VALUES (
              ingredient_record.ingredient_id,
              base_quantity,
              ingredient_record.unit_type,
              ARRAY[recipe_record.recipe_id],
              ingredient_record.notes
            )
            ON CONFLICT (ingredient_id, unit_type) DO UPDATE
            SET 
              total_base_quantity = temp_ingredient_aggregation.total_base_quantity + EXCLUDED.total_base_quantity,
              source_recipes = array_cat(temp_ingredient_aggregation.source_recipes, EXCLUDED.source_recipes),
              notes = CASE 
                WHEN temp_ingredient_aggregation.notes IS NULL THEN EXCLUDED.notes
                WHEN EXCLUDED.notes IS NULL THEN temp_ingredient_aggregation.notes
                WHEN temp_ingredient_aggregation.notes = EXCLUDED.notes THEN temp_ingredient_aggregation.notes
                ELSE temp_ingredient_aggregation.notes || '; ' || EXCLUDED.notes
              END;
          END;
        END IF;
      END LOOP;
    END;
  END LOOP;
  
  -- Now convert aggregated base quantities back to appropriate display units
  -- Each ingredient+unit_type combination will become a separate grocery list item
  FOR ingredient_record IN
    SELECT * FROM temp_ingredient_aggregation
  LOOP
    -- Find the most commonly used unit for this ingredient across all recipes
    -- or use a default unit based on the quantity
    SELECT unit_id INTO preferred_unit_id
    FROM (
      -- First priority: most frequently used unit for this ingredient
      SELECT ri.unit_id, COUNT(*) as usage_count
      FROM recipe_ingredients ri
      JOIN units u ON ri.unit_id = u.id
      WHERE ri.ingredient_id = ingredient_record.ingredient_id
        AND u.type = ingredient_record.unit_type
      GROUP BY ri.unit_id
      ORDER BY usage_count DESC
      LIMIT 1
    ) preferred_units;
    
    -- If no preferred unit found, select a reasonable default based on quantity
    IF preferred_unit_id IS NULL THEN
      SELECT id INTO preferred_unit_id
      FROM units
      WHERE type = ingredient_record.unit_type
        AND system IN ('metric', 'imperial')  -- Prefer standard systems
      ORDER BY 
        CASE 
          -- For small quantities, prefer smaller units (larger conversion factor)
          WHEN ingredient_record.total_base_quantity < 100 THEN -base_conversion_factor
          -- For large quantities, prefer larger units (smaller conversion factor)
          ELSE base_conversion_factor
        END,
        display_order ASC
      LIMIT 1;
    END IF;
    
    -- Convert from base unit back to preferred unit
    SELECT 
      CASE 
        WHEN u.base_conversion_factor IS NOT NULL AND u.base_conversion_factor > 0 THEN
          ingredient_record.total_base_quantity / u.base_conversion_factor
        ELSE
          ingredient_record.total_base_quantity
      END INTO converted_quantity
    FROM units u
    WHERE u.id = preferred_unit_id;
    
    -- Insert the consolidated item
    INSERT INTO grocery_list_items (
      grocery_list_id,
      ingredient_id,
      quantity,
      unit_id,
      notes,
      is_manual,
      source_recipes
    ) VALUES (
      list_id,
      ingredient_record.ingredient_id,
      ROUND(converted_quantity, 2),  -- Round to 2 decimal places for cleaner display
      preferred_unit_id,
      ingredient_record.notes,
      false,
      ingredient_record.source_recipes
    );
  END LOOP;
  
  -- Handle ingredients with no base conversion factor
  FOR ingredient_record IN
    SELECT * FROM temp_ingredient_no_conversion
  LOOP
    -- Insert items without base conversion as separate grocery list items
    INSERT INTO grocery_list_items (
      grocery_list_id,
      ingredient_id,
      quantity,
      unit_id,
      notes,
      is_manual,
      source_recipes
    ) VALUES (
      list_id,
      ingredient_record.ingredient_id,
      ROUND(ingredient_record.total_quantity, 2),
      ingredient_record.unit_id,
      ingredient_record.notes,
      false,
      ingredient_record.source_recipes
    );
  END LOOP;
  
  -- Handle ingredients with null quantities
  FOR ingredient_record IN
    SELECT * FROM temp_null_quantity_ingredients
  LOOP
    -- Insert items with null quantities (like "to taste" ingredients)
    INSERT INTO grocery_list_items (
      grocery_list_id,
      ingredient_id,
      quantity,
      unit_id,
      notes,
      is_manual,
      source_recipes
    ) VALUES (
      list_id,
      ingredient_record.ingredient_id,
      NULL,  -- Keep quantity as NULL
      ingredient_record.unit_id,
      ingredient_record.notes,
      false,
      ingredient_record.source_recipes
    );
  END LOOP;

  -- Explicitly drop temporary tables (optional cleanup)
  DROP TABLE IF EXISTS temp_ingredient_aggregation;
  DROP TABLE IF EXISTS temp_ingredient_no_conversion;
  DROP TABLE IF EXISTS temp_null_quantity_ingredients;
  
  -- Update the grocery list timestamp
  UPDATE grocery_lists SET updated_at = now() WHERE id = list_id;
END;$function$
;

CREATE OR REPLACE FUNCTION public.remove_recipe_from_grocery_list(list_id uuid, recipe_id bigint)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$BEGIN
    -- Delete the specific recipe from the grocery list
    DELETE FROM grocery_list_recipes 
    WHERE grocery_list_id = list_id 
      AND recipe_list_recipes.recipe_id = recipe_id;
    
    -- Return true if a row was deleted, false otherwise
    RETURN FOUND;
END;$function$
;

CREATE OR REPLACE FUNCTION public.trigger_delete_old_anonymous_users()
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    deleted_count INTEGER;
BEGIN
    SELECT deleted_count INTO deleted_count 
    FROM delete_old_anonymous_users();
    
    -- Optional: You can add logging or notification here
    RAISE NOTICE 'Deleted % old anonymous users', deleted_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.trigger_regenerate_grocery_list()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF TG_OP = 'INSERT' OR TG_OP = 'UPDATE' THEN
    PERFORM regenerate_grocery_list_items(NEW.grocery_list_id);
    RETURN NEW;
  ELSIF TG_OP = 'DELETE' THEN
    PERFORM regenerate_grocery_list_items(OLD.grocery_list_id);
    RETURN OLD;
  END IF;
  RETURN NULL;
END;
$function$
;

