  create policy "Enable read access for all users"
  on "public"."grocery_aisles"
  as permissive
  for select
  to public
using (true);



  create policy "Users can manage own grocery list items"
  on "public"."grocery_list_items"
  as permissive
  for all
  to public
using ((EXISTS ( SELECT 1
   FROM public.grocery_lists gl
  WHERE ((gl.id = grocery_list_items.grocery_list_id) AND (gl.user_id = auth.uid())))));



  create policy "Users can manage own grocery list recipes"
  on "public"."grocery_list_recipes"
  as permissive
  for all
  to public
using ((EXISTS ( SELECT 1
   FROM public.grocery_lists gl
  WHERE ((gl.id = grocery_list_recipes.grocery_list_id) AND (gl.user_id = auth.uid())))));



  create policy "Users can manage own grocery lists"
  on "public"."grocery_lists"
  as permissive
  for all
  to public
using ((auth.uid() = user_id));



  create policy "Enable insert for authenticated users only"
  on "public"."ingredients"
  as permissive
  for insert
  to authenticated
with check (true);



  create policy "Enable read access for all users"
  on "public"."ingredients"
  as permissive
  for select
  to public
using (true);



  create policy "Enable insert for authenticated users only"
  on "public"."recipe_ingredients"
  as permissive
  for insert
  to authenticated
with check (true);



  create policy "Enable read access for all users"
  on "public"."recipe_ingredients"
  as permissive
  for select
  to public
using (true);



  create policy "Enable insert for authenticated users only"
  on "public"."recipes"
  as permissive
  for insert
  to authenticated
with check (true);



  create policy "Enable read access for all users"
  on "public"."recipes"
  as permissive
  for select
  to public
using (true);



  create policy "Enable users to view their own data only"
  on "public"."recipes"
  as permissive
  for select
  to authenticated
using ((( SELECT auth.uid() AS uid) = created_by));



  create policy "Enable read access for all users"
  on "public"."subaisle_positions"
  as permissive
  for select
  to public
using (true);



  create policy "Enable read access for all users"
  on "public"."units"
  as permissive
  for select
  to public
using (true);


CREATE TRIGGER grocery_list_recipes_change_trigger AFTER INSERT OR DELETE OR UPDATE ON public.grocery_list_recipes FOR EACH ROW EXECUTE FUNCTION public.trigger_regenerate_grocery_list();

CREATE TRIGGER on_anonymous_user_create BEFORE INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.handle_new_anonymous_user();


  create policy "Allow INSERT for authenticated users only"
  on "storage"."objects"
  as permissive
  for insert
  to authenticated
with check (true);



